scripts.inline:
#!/bin/bash
set -euo pipefail
RELEASE=${1:?Usage: helm-install.sh <release> <chart> [values-file] [namespace]}
CHART=${2:?Usage: helm-install.sh <release> <chart> [values-file] [namespace]}
VALUES_FILE=${3:-}
NS=${4:-${HELM_NAMESPACE:-default}}

ARGS=(upgrade --install "$RELEASE" "$CHART" --namespace "$NS" --create-namespace --wait --timeout 5m)

if [ -n "$VALUES_FILE" ]; then
  ARGS+=(-f "$VALUES_FILE")
fi

echo "Installing/upgrading $RELEASE from $CHART in namespace $NS"
helm "${ARGS[@]}"

echo ""
echo "Release status:"
helm status "$RELEASE" -n "$NS"
